import { useState, useEffect, useCallback } from 'react';
import { getApiBase } from '../utils/platform';
import usePageTitle from '../hooks/usePageTitle';
import s from './AIInsightsPage.module.css';

function authHeaders() {
  const token = localStorage.getItem('aura_token');
  return token ? { Authorization: `Bearer ${token}` } : {};
}

// ── Status badge ─────────────────────────────────────────────
function ProviderBadge({ provider, model }) {
  const cls = provider === 'gemini' ? s.providerBadgeGemini : s.providerBadgePurple;
  return (
    <span className={cls}>
      {provider === 'gemini' ? '\u25C6' : '\u25CF'} {model || provider}
    </span>
  );
}

function CostBadge({ cost }) {
  if (!cost && cost !== 0) return null;
  return (
    <span className={s.costBadge}>
      ${cost < 0.01 ? cost.toFixed(6) : cost.toFixed(4)}
    </span>
  );
}

function TokenBadge({ tokens: t }) {
  if (!t) return null;
  return (
    <span className={s.tokenBadge}>
      {t.toLocaleString()} tok
    </span>
  );
}

// ── Card wrapper ─────────────────────────────────────────────
function Card({ title, icon, children, headerRight, loading, error }) {
  return (
    <div className={s.card}>
      <div className={s.cardHeader}>
        <div className={s.cardTitleWrap}>
          <span className={s.cardIcon}>{icon}</span>
          <span className={s.cardTitle}>{title}</span>
        </div>
        {headerRight && <div className={s.cardHeaderRight}>{headerRight}</div>}
      </div>
      <div className={s.cardBody}>
        {loading ? (
          <div className={s.loadingText}>Loading...</div>
        ) : error ? (
          <div className={s.errorText}>{error}</div>
        ) : children}
      </div>
    </div>
  );
}

// ── Market Brief section ─────────────────────────────────────
function MarketBrief() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetch_ = useCallback(async () => {
    setLoading(true); setError(null);
    try {
      const res = await fetch(`${getApiBase()}/api/ai/market-brief`, { headers: authHeaders() });
      if (!res.ok) throw new Error(`${res.status}: ${(await res.json()).detail || res.statusText}`);
      setData(await res.json());
    } catch (e) { setError(e.message); }
    setLoading(false);
  }, []);

  return (
    <Card
      title="Daily Market Brief" icon="\uD83D\uDCCA"
      loading={loading} error={error}
      headerRight={
        <>
          {data && <ProviderBadge provider={data.provider} model={data.model} />}
          {data && <CostBadge cost={data.cost_usd} />}
          {data && <TokenBadge tokens={data.tokens_used} />}
          <button onClick={fetch_} disabled={loading} className={s.btnBlue}>
            {data ? 'Refresh' : 'Generate'}
          </button>
        </>
      }
    >
      {data ? (
        <div className={s.briefContent}>{data.brief}</div>
      ) : (
        <div className={s.placeholder}>
          Click <b>Generate</b> to create today's AI market brief. Available on all tiers — powered by Gemini Flash.
        </div>
      )}
    </Card>
  );
}

// ── Strategy Summary section ─────────────────────────────────
function StrategySummary() {
  const [strategies, setStrategies] = useState([]);
  const [selected, setSelected] = useState('');
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${getApiBase()}/api/strategies`, { headers: authHeaders() });
        if (res.ok) {
          const d = await res.json();
          const list = (d.strategies || d || []).map(st => st.name || st.key || st).filter(Boolean);
          setStrategies(list.slice(0, 50));
          if (list.length > 0) setSelected(list[0]);
        }
      } catch {}
    })();
  }, []);

  const fetch_ = useCallback(async () => {
    if (!selected) return;
    setLoading(true); setError(null);
    try {
      const res = await fetch(`${getApiBase()}/api/ai/strategy-summary/${encodeURIComponent(selected)}`, { headers: authHeaders() });
      if (!res.ok) throw new Error(`${res.status}: ${(await res.json()).detail || res.statusText}`);
      setData(await res.json());
    } catch (e) { setError(e.message); }
    setLoading(false);
  }, [selected]);

  return (
    <Card
      title="Strategy Summary" icon="\uD83E\uDDE0"
      loading={loading} error={error}
      headerRight={
        <>
          {data && <ProviderBadge provider={data.provider} />}
          {data && <TokenBadge tokens={data.tokens_used} />}
          <select
            value={selected}
            onChange={e => { setSelected(e.target.value); setData(null); }}
            className={s.selectInput}
          >
            {strategies.map(st => <option key={st} value={st}>{st}</option>)}
          </select>
          <button onClick={fetch_} disabled={loading || !selected} className={s.btnBlue}>
            Summarize
          </button>
        </>
      }
    >
      {data ? (
        <div className={s.briefContent}>
          <div className={s.strategyLabel}>{data.strategy}</div>
          {data.summary}
        </div>
      ) : (
        <div className={s.placeholder}>
          Select a strategy and click <b>Summarize</b> for a plain-English explanation. Active+ tiers.
        </div>
      )}
    </Card>
  );
}

