// ── Journal Insights section ─────────────────────────────────
function JournalInsights() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [limit, setLimit] = useState(20);

  const fetch_ = useCallback(async () => {
    setLoading(true); setError(null);
    try {
      const res = await fetch(`${getApiBase()}/api/ai/journal-insights?limit=${limit}`, { headers: authHeaders() });
      if (!res.ok) throw new Error(`${res.status}: ${(await res.json()).detail || res.statusText}`);
      setData(await res.json());
    } catch (e) { setError(e.message); }
    setLoading(false);
  }, [limit]);

  return (
    <Card
      title="Journal Behavioral Analysis" icon="\uD83D\uDCD3"
      loading={loading} error={error}
      headerRight={
        <>
          {data && <ProviderBadge provider={data.provider} />}
          {data && <TokenBadge tokens={data.tokens_used} />}
          {data && <span className={s.entryCountBadge}>{data.entry_count} entries</span>}
          <select
            value={limit}
            onChange={e => setLimit(Number(e.target.value))}
            className={s.selectInput}
            style={{ maxWidth: 'none' }}
          >
            <option value={10}>Last 10</option>
            <option value={20}>Last 20</option>
            <option value={50}>Last 50</option>
            <option value={100}>Last 100</option>
          </select>
          <button onClick={fetch_} disabled={loading} className={s.btnAmber}>
            Analyze
          </button>
        </>
      }
    >
      {data ? (
        <div className={s.briefContent}>{data.analysis}</div>
      ) : (
        <div className={s.placeholder}>
          Analyze your trade journal entries for behavioral patterns, emotional triggers, and recurring mistakes. Active+ tiers.
        </div>
      )}
    </Card>
  );
}

// ── Provider Status section ──────────────────────────────────
function ProviderStatus() {
  const [data, setData] = useState(null);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch(`${getApiBase()}/api/ai/status`);
        if (res.ok) setData(await res.json());
      } catch {}
    })();
  }, []);

  if (!data) return null;

  return (
    <div className={s.statusGrid}>
      <div className={s.statusCardFlex}>
        <div className={data.gemini_available ? s.statusDotGreen : s.statusDotRed} />
        <div>
          <div className={s.statusName}>Gemini</div>
          <div className={s.statusDetail}>
            {data.gemini_available ? 'Flash + Pro' : 'Unavailable'}
          </div>
        </div>
      </div>
      <div className={s.statusCardFlex}>
        <div className={data.openai_available ? s.statusDotGreen : s.statusDotRed} />
        <div>
          <div className={s.statusName}>OpenAI</div>
          <div className={s.statusDetail}>
            {data.openai_available ? 'GPT-4.1' : 'Not configured'}
          </div>
        </div>
      </div>
      <div className={s.statusCard}>
        <div className={s.statusName}>Routing</div>
        <div className={s.statusDetail}>
          Cheap: {data.preferred_cheap} · Deep: {data.preferred_deep}
        </div>
      </div>
      <div className={s.statusCard}>
        <div className={s.statusName}>Cost</div>
        <div className={s.statusCostDetail}>
          Flash $0.15/1M · Pro $1.25/1M
        </div>
      </div>
    </div>
  );
}

// ── Main page ────────────────────────────────────────────────
export default function AIInsightsPage() {
  usePageTitle('AI Insights');

  return (
    <div className={s.page}>
      <div className={s.headerSection}>
        <h1 className={s.title}>AI Insights</h1>
        <p className={s.subtitle}>
          Gemini-powered market intelligence, strategy analysis, and behavioral coaching.
        </p>
      </div>

      <ProviderStatus />

      <div className={s.cardStack}>
        <MarketBrief />
        <StrategySummary />
        <BacktestReport />
        <JournalInsights />
      </div>
    </div>
  );
}
